// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/update-lambda-config/result`);
  const configBody = await configGet.json();

  if (!configBody.FunctionArn) {
    console.log("Lambda configuration update failed!");
    throw new Error("Lambda configuration update failed!");
  }

  console.log("Lambda function updated successfully");
  console.log("New Memory: " + configBody.MemorySize + " MB");
  console.log("New Timeout: " + configBody.Timeout + " seconds");

  return configBody;
}
